final:
module RefModule(
    input wire clk,
    input wire rst_n,
    input wire d,
    output reg [7:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        q <= 8'd0;
    else
        q <= {d, q[7:1]};
end

endmodule
